<PageTitle>Job Application</PageTitle>

<div class="container py-4">
    <h2 class="mb-4">Job Application</h2>

    @* ── Step Indicator Bar ── *@
    <nav class="step-indicator mb-4" aria-label="Application steps">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var state = GetStepState(step);
            <button class="step-item @state"
                    disabled="@(state == "future")"
                    @onclick="() => GoToStep(step)"
                    aria-current="@(step == currentStep ? "step" : null)">
                <span class="step-circle">
                    @if (state == "completed")
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @(step + 1)
                    }
                </span>
                <span class="step-label">@StepNames[step]</span>
            </button>
        }
    </nav>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger" role="alert">@errorMessage</div>
    }

    @* ── Step Content ── *@
    @if (submitted)
    {
        <div class="card text-center p-5">
            <div class="text-success mb-3" style="font-size:3rem;">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@applicationId</strong></p>
            <p>Thank you for applying. We will review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        switch (currentStep)
        {
            case 0:
                @RenderPersonalInfo()
                break;
            case 1:
                @RenderWorkHistory()
                break;
            case 2:
                @RenderReferences()
                break;
            case 3:
                @RenderCoverLetter()
                break;
            case 4:
                @RenderReview()
                break;
        }
    }
</div>

