                        <p class="mb-0 mt-1">@entry.Description</p>
                    }
                </div>
            }
        </div>
        <hr />

        @* References *@
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h5>References</h5>
                <button class="btn btn-sm btn-link" @onclick="() => GoToStep(2)">Edit</button>
            </div>
            @foreach (var r in references)
            {
                <div class="mb-2 ps-2 border-start border-3">
                    <strong>@r.Name</strong> — @r.Relationship<br />
                    <small class="text-muted">@r.Email · @r.Phone</small>
                </div>
            }
        </div>
        <hr />

        @* Cover Letter *@
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h5>Cover Letter</h5>
                <button class="btn btn-sm btn-link" @onclick="() => GoToStep(3)">Edit</button>
            </div>
            <p style="white-space: pre-wrap;">@coverLetter</p>
        </div>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
            <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@isProcessing">
                @if (isProcessing) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Submit Application
            </button>
        </div>
    </div>;
}

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private const int MaxCoverLetterChars = 2000;

    // State
    private int currentStep;
    private int highestCompletedStep = -1;
    private string? errorMessage;
    private bool isProcessing;
    private bool emailValidating;
    private bool submitted;
    private int applicationId;

    // Step 1
    private string fullName = string.Empty;
    private string email = string.Empty;
    private string phone = string.Empty;
    private string address = string.Empty;

    // Step 2
    private List<WorkEntryModel> workEntries = [new()];

    // Step 3
    private List<ReferenceModel> references = [new(), new()];

    // Step 4
    private string coverLetter = string.Empty;

    // ── Navigation ──

    private string GetStepState(int step)
    {
        if (step == currentStep) return "active";
        if (step <= highestCompletedStep) return "completed";
        return "future";
    }

    private void GoToStep(int step)
    {
        if (step <= highestCompletedStep || step == currentStep)
        {
            errorMessage = null;
            currentStep = step;
        }
    }

    private void PreviousStep()
    {
        errorMessage = null;
        if (currentStep > 0) currentStep--;
    }

    private void AdvanceStep()
    {
        if (currentStep > highestCompletedStep)
            highestCompletedStep = currentStep;
        currentStep++;
        errorMessage = null;
    }

    // ── Step 1 validation ──

    private async Task NextFromPersonalInfo()
    {
        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email)
            || string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
        {
            errorMessage = "Please fill in all required fields.";
            return;
        }

        isProcessing = true;
        emailValidating = true;
        errorMessage = null;

        try
        {
            var valid = await ApplicationService.ValidateEmailAsync(email);
            if (!valid)
            {
                errorMessage = "The email address is not valid. Please check and try again.";
                return;
            }
            AdvanceStep();
        }
        finally
        {
            isProcessing = false;
            emailValidating = false;
        }
    }

    // ── Step 2 helpers ──

    private void AddWorkEntry() => workEntries.Add(new());

    private void RemoveWorkEntry(int index)
    {
        if (workEntries.Count > 1) workEntries.RemoveAt(index);
    }

    private void UpdateWork(int index, WorkEntryModel updated) => workEntries[index] = updated;

    private void NextFromWorkHistory()
    {
        foreach (var e in workEntries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)
                || e.StartDate == default)
            {
                errorMessage = "Please fill in company, title, and start date for all positions.";
                return;
            }
        }
        AdvanceStep();
    }

    // ── Step 3 helpers ──

    private void AddReference()
    {
        if (references.Count < 3) references.Add(new());
    }

    private void RemoveReference(int index)
    {
        if (references.Count > 2) references.RemoveAt(index);
    }

    private void UpdateRef(int index, ReferenceModel updated) => references[index] = updated;

    private void NextFromReferences()
    {
        foreach (var r in references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }
        AdvanceStep();
    }

    // ── Step 4 ──

    private void NextFromCoverLetter()
    {
        if (string.IsNullOrWhiteSpace(coverLetter))
        {
            errorMessage = "Please write a cover letter before continuing.";
            return;
        }
        AdvanceStep();
    }

    // ── Step 5 ──

    private async Task SubmitApplication()
    {
        isProcessing = true;
        errorMessage = null;

        try
        {
            var personal = new PersonalInfo(fullName, email, phone, address);
            var work = new WorkHistory(workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
            var refs = references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
            var app = new JobApplication(personal, work, refs, coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(app);
            submitted = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isProcessing = false;
        }
    }

    // ── Helpers ──

    private static string FormatDate(DateTime date) =>
        date == default ? string.Empty : date.ToString("yyyy-MM-dd");

    private static string FormatDate(DateTime? date) =>
        date?.ToString("yyyy-MM-dd") ?? string.Empty;

    private static DateTime ParseDate(string? value) =>
        DateTime.TryParse(value, out var d) ? d : default;

    private static DateTime? ParseNullableDate(string? value) =>
        DateTime.TryParse(value, out var d) ? d : null;

    // ── Mutable models for form binding ──

    private record WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }

    private record ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}
