+@inject IApplicationService ApplicationService
+
+<PageTitle>Job Application</PageTitle>
+
+<div class="container py-4">
+    <h2 class="mb-4">Job Application</h2>
+
+    @* ── Step Indicator Bar ── *@
+    <nav class="step-indicator mb-4" aria-label="Application steps">
+        @for (int i = 0; i < StepNames.Length; i++)
+        {
+            var step = i;
+            var state = GetStepState(step);
+            <button class="step-item @state"
+                    disabled="@(state == "future")"
+                    @onclick="() => GoToStep(step)"
+                    aria-current="@(step == currentStep ? "step" : null)">
+                <span class="step-circle">
+                    @if (state == "completed")
+                    {
+                        <span>&#10003;</span>
+                    }
+                    else
+                    {
+                        @(step + 1)
+                    }
+                </span>
+                <span class="step-label">@StepNames[step]</span>
+            </button>
+        }
+    </nav>
+
+    @if (!string.IsNullOrEmpty(errorMessage))
+    {
+        <div class="alert alert-danger" role="alert">@errorMessage</div>
+    }
+
+    @* ── Step Content ── *@
+    @if (submitted)
+    {
+        <div class="card text-center p-5">
+            <div class="text-success mb-3" style="font-size:3rem;">&#10003;</div>
+            <h3>Application Submitted!</h3>
+            <p class="lead">Your application ID is <strong>#@applicationId</strong></p>
+            <p>Thank you for applying. We will review your application and get back to you soon.</p>
+        </div>
+    }
+    else
+    {
+        switch (currentStep)
+        {
+            case 0:
+                @RenderPersonalInfo()
+                break;
+            case 1:
+                @RenderWorkHistory()
+                break;
+            case 2:
+                @RenderReferences()
+                break;
+            case 3:
+                @RenderCoverLetter()
+                break;
+            case 4:
+                @RenderReview()
+                break;
+        }
+    }
+</div>
+
+@* ─────────── Step 1: Personal Info ─────────── *@
+@{ RenderFragment RenderPersonalInfo() =>
+    @<div class="card p-4">
+        <h4 class="mb-3">Personal Information</h4>
+        <div class="mb-3">
+            <label class="form-label">Full Name <span class="text-danger">*</span></label>
+            <input class="form-control" @bind="fullName" placeholder="Jane Doe" />
+        </div>
+        <div class="mb-3">
+            <label class="form-label">Email <span class="text-danger">*</span></label>
+            <input type="email" class="form-control" @bind="email" placeholder="jane@example.com" />
+            @if (emailValidating)
+            {
+                <div class="form-text text-muted">Validating email…</div>
+            }
+        </div>
+        <div class="mb-3">
+            <label class="form-label">Phone <span class="text-danger">*</span></label>
+            <input type="tel" class="form-control" @bind="phone" placeholder="(555) 123-4567" />
+        </div>
+        <div class="mb-3">
+            <label class="form-label">Address <span class="text-danger">*</span></label>
+            <textarea class="form-control" rows="2" @bind="address" placeholder="123 Main St, City, State ZIP"></textarea>
+        </div>
+        <div class="d-flex justify-content-end">
+            <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@isProcessing">
+                @if (isProcessing) { <span class="spinner-border spinner-border-sm me-1"></span> }
+                Next
+            </button>
+        </div>
+    </div>;
+}
+
+@* ─────────── Step 2: Work History ─────────── *@
+@{ RenderFragment RenderWorkHistory() =>
+    @<div class="card p-4">
+        <h4 class="mb-3">Work History</h4>
+        @for (int i = 0; i < workEntries.Count; i++)
+        {
+            var idx = i;
+            var entry = workEntries[idx];
+            <div class="border rounded p-3 mb-3 position-relative">
+                <h6 class="text-muted">Position @(idx + 1)</h6>
+                @if (workEntries.Count > 1)
+                {
+                    <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
+                            @onclick="() => RemoveWorkEntry(idx)">Remove</button>
+                }
+                <div class="row g-3">
+                    <div class="col-md-6">
+                        <label class="form-label">Company <span class="text-danger">*</span></label>
+                        <input class="form-control" value="@entry.Company"
+                               @onchange="e => UpdateWork(idx, entry with { Company = (string?)e.Value ?? string.Empty })" />
+                    </div>
+                    <div class="col-md-6">
+                        <label class="form-label">Job Title <span class="text-danger">*</span></label>
+                        <input class="form-control" value="@entry.Title"
+                               @onchange="e => UpdateWork(idx, entry with { Title = (string?)e.Value ?? string.Empty })" />
+                    </div>
+                    <div class="col-md-4">
+                        <label class="form-label">Start Date <span class="text-danger">*</span></label>
+                        <input type="date" class="form-control" value="@FormatDate(entry.StartDate)"
+                               @onchange="e => UpdateWork(idx, entry with { StartDate = ParseDate((string?)e.Value) })" />
+                    </div>
+                    <div class="col-md-4">
+                        <label class="form-label">End Date</label>
+                        <input type="date" class="form-control" value="@FormatDate(entry.EndDate)"
+                               disabled="@entry.IsCurrent"
+                               @onchange="e => UpdateWork(idx, entry with { EndDate = ParseNullableDate((string?)e.Value) })" />
+                    </div>
+                    <div class="col-md-4 d-flex align-items-end">
+                        <div class="form-check mb-2">
+                            <input class="form-check-input" type="checkbox" checked="@entry.IsCurrent"
+                                   @onchange="e => UpdateWork(idx, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = null })" />
+                            <label class="form-check-label">Currently working here</label>
+                        </div>
+                    </div>
+                    <div class="col-12">
+                        <label class="form-label">Description</label>
+                        <textarea class="form-control" rows="2" value="@entry.Description"
+                                  @onchange="e => UpdateWork(idx, entry with { Description = (string?)e.Value ?? string.Empty })"></textarea>
+                    </div>
+                </div>
+            </div>
+        }
+        <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">
+            + Add Another Position
+        </button>
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+            <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
+        </div>
+    </div>;
+}
+
+@* ─────────── Step 3: References ─────────── *@
+@{ RenderFragment RenderReferences() =>
+    @<div class="card p-4">
+        <h4 class="mb-3">References</h4>
+        @for (int i = 0; i < references.Count; i++)
+        {
+            var idx = i;
+            var r = references[idx];
+            <div class="border rounded p-3 mb-3 position-relative">
+                <h6 class="text-muted">Reference @(idx + 1)</h6>
+                @if (references.Count > 2)
+                {
+                    <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
+                            @onclick="() => RemoveReference(idx)">Remove</button>
+                }
+                <div class="row g-3">
+                    <div class="col-md-6">
+                        <label class="form-label">Name <span class="text-danger">*</span></label>
+                        <input class="form-control" value="@r.Name"
+                               @onchange="e => UpdateRef(idx, r with { Name = (string?)e.Value ?? string.Empty })" />
+                    </div>
+                    <div class="col-md-6">
+                        <label class="form-label">Relationship <span class="text-danger">*</span></label>
+                        <input class="form-control" value="@r.Relationship"
+                               @onchange="e => UpdateRef(idx, r with { Relationship = (string?)e.Value ?? string.Empty })" />
+                    </div>
+                    <div class="col-md-6">
+                        <label class="form-label">Email <span class="text-danger">*</span></label>
+                        <input type="email" class="form-control" value="@r.Email"
+                               @onchange="e => UpdateRef(idx, r with { Email = (string?)e.Value ?? string.Empty })" />
+                    </div>
+                    <div class="col-md-6">
+                        <label class="form-label">Phone <span class="text-danger">*</span></label>
+                        <input type="tel" class="form-control" value="@r.Phone"
+                               @onchange="e => UpdateRef(idx, r with { Phone = (string?)e.Value ?? string.Empty })" />
+                    </div>
+                </div>
+            </div>
+        }
+        @if (references.Count < 3)
+        {
+            <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
+                + Add Reference
+            </button>
+        }
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+            <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
+        </div>
+    </div>;
+}
+
+@* ─────────── Step 4: Cover Letter ─────────── *@
+@{ RenderFragment RenderCoverLetter() =>
+    @<div class="card p-4">
+        <h4 class="mb-3">Cover Letter</h4>
+        <div class="mb-2">
+            <textarea class="form-control" rows="10" maxlength="@MaxCoverLetterChars"
+                      @bind="coverLetter" @bind:event="oninput"
+                      placeholder="Tell us why you're a great fit for this position…"></textarea>
+        </div>
+        <div class="form-text text-end mb-3">
+            @(coverLetter?.Length ?? 0) / @MaxCoverLetterChars characters
+        </div>
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+            <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
+        </div>
+    </div>;
+}
+
+@* ─────────── Step 5: Review & Submit ─────────── *@
+@{ RenderFragment RenderReview() =>
+    @<div class="card p-4">
+        <h4 class="mb-3">Review Your Application</h4>
+
+        @* Personal Info *@
+        <div class="mb-4">
+            <div class="d-flex justify-content-between align-items-center">
+                <h5>Personal Information</h5>
+                <button class="btn btn-sm btn-link" @onclick="() => GoToStep(0)">Edit</button>
+            </div>
+            <dl class="row mb-0">
+                <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@fullName</dd>
+                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@email</dd>
+                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@phone</dd>
+                <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@address</dd>
+            </dl>
+        </div>
+        <hr />
+
+        @* Work History *@
+        <div class="mb-4">
+            <div class="d-flex justify-content-between align-items-center">
+                <h5>Work History</h5>
+                <button class="btn btn-sm btn-link" @onclick="() => GoToStep(1)">Edit</button>
+            </div>
+            @foreach (var entry in workEntries)
+            {
+                <div class="mb-2 ps-2 border-start border-3">
+                    <strong>@entry.Title</strong> at @entry.Company<br />
+                    <small class="text-muted">
+                        @entry.StartDate.ToString("MMM yyyy") –
+                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
+                    </small>
+                    @if (!string.IsNullOrWhiteSpace(entry.Description))
+                    {
+                        <p class="mb-0 mt-1">@entry.Description</p>
+                    }
+                </div>
+            }
+        </div>
+        <hr />
+
+        @* References *@
+        <div class="mb-4">
+            <div class="d-flex justify-content-between align-items-center">
+                <h5>References</h5>
+                <button class="btn btn-sm btn-link" @onclick="() => GoToStep(2)">Edit</button>
+            </div>
+            @foreach (var r in references)
+            {
+                <div class="mb-2 ps-2 border-start border-3">
+                    <strong>@r.Name</strong> — @r.Relationship<br />
+                    <small class="text-muted">@r.Email · @r.Phone</small>
+                </div>
+            }
+        </div>
+        <hr />
+
+        @* Cover Letter *@
+        <div class="mb-4">
+            <div class="d-flex justify-content-between align-items-center">
+                <h5>Cover Letter</h5>
+                <button class="btn btn-sm btn-link" @onclick="() => GoToStep(3)">Edit</button>
+            </div>
+            <p style="white-space: pre-wrap;">@coverLetter</p>
+        </div>
+
+        <div class="d-flex justify-content-between">
+            <button class="btn btn-secondary" @onclick="PreviousStep">Back</button>
+            <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@isProcessing">
+                @if (isProcessing) { <span class="spinner-border spinner-border-sm me-1"></span> }
+                Submit Application
+            </button>
+        </div>
+    </div>;
+}
+
+@code {
+    private static readonly string[] StepNames =
+        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];
+
+    private const int MaxCoverLetterChars = 2000;
+
+    // State
+    private int currentStep;
+    private int highestCompletedStep = -1;
+    private string? errorMessage;
+    private bool isProcessing;
+    private bool emailValidating;
+    private bool submitted;
+    private int applicationId;
+
+    // Step 1
+    private string fullName = string.Empty;
+    private string email = string.Empty;
+    private string phone = string.Empty;
+    private string address = string.Empty;
+
+    // Step 2
+    private List<WorkEntryModel> workEntries = [new()];
+
+    // Step 3
+    private List<ReferenceModel> references = [new(), new()];
+
+    // Step 4
+    private string coverLetter = string.Empty;
+
+    // ── Navigation ──
+
+    private string GetStepState(int step)
+    {
+        if (step == currentStep) return "active";
+        if (step <= highestCompletedStep) return "completed";
+        return "future";
+    }
+
+    private void GoToStep(int step)
+    {
+        if (step <= highestCompletedStep || step == currentStep)
+        {
+            errorMessage = null;
+            currentStep = step;
+        }
+    }
+
+    private void PreviousStep()
+    {
+        errorMessage = null;
+        if (currentStep > 0) currentStep--;
+    }
+
+    private void AdvanceStep()
+    {
+        if (currentStep > highestCompletedStep)
+            highestCompletedStep = currentStep;
+        currentStep++;
+        errorMessage = null;
+    }
+
+    // ── Step 1 validation ──
+
+    private async Task NextFromPersonalInfo()
+    {
+        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email)
+            || string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
+        {
+            errorMessage = "Please fill in all required fields.";
+            return;
+        }
+
+        isProcessing = true;
+        emailValidating = true;
+        errorMessage = null;
+
+        try
+        {
+            var valid = await ApplicationService.ValidateEmailAsync(email);
+            if (!valid)
+            {
+                errorMessage = "The email address is not valid. Please check and try again.";
+                return;
+            }
+            AdvanceStep();
+        }
+        finally
+        {
+            isProcessing = false;
+            emailValidating = false;
+        }
+    }
+
+    // ── Step 2 helpers ──
+
+    private void AddWorkEntry() => workEntries.Add(new());
+
+    private void RemoveWorkEntry(int index)
+    {
+        if (workEntries.Count > 1) workEntries.RemoveAt(index);
+    }
+
+    private void UpdateWork(int index, WorkEntryModel updated) => workEntries[index] = updated;
+
+    private void NextFromWorkHistory()
+    {
+        foreach (var e in workEntries)
+        {
+            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)
+                || e.StartDate == default)
+            {
+                errorMessage = "Please fill in company, title, and start date for all positions.";
+                return;
+            }
+        }
+        AdvanceStep();
+    }
+
+    // ── Step 3 helpers ──
+
+    private void AddReference()
+    {
+        if (references.Count < 3) references.Add(new());
+    }
+
+    private void RemoveReference(int index)
+    {
+        if (references.Count > 2) references.RemoveAt(index);
+    }
+
+    private void UpdateRef(int index, ReferenceModel updated) => references[index] = updated;
+
+    private void NextFromReferences()
+    {
+        foreach (var r in references)
+        {
+            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
+                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
+            {
+                errorMessage = "Please fill in all fields for each reference.";
+                return;
+            }
+        }
+        AdvanceStep();
+    }
+
+    // ── Step 4 ──
+
+    private void NextFromCoverLetter()
+    {
+        if (string.IsNullOrWhiteSpace(coverLetter))
+        {
+            errorMessage = "Please write a cover letter before continuing.";
+            return;
+        }
+        AdvanceStep();
+    }
+
+    // ── Step 5 ──
+
+    private async Task SubmitApplication()
+    {
+        isProcessing = true;
+        errorMessage = null;
+
+        try
+        {
+            var personal = new PersonalInfo(fullName, email, phone, address);
+            var work = new WorkHistory(workEntries.Select(e =>
+                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList());
+            var refs = references.Select(r =>
+                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
+            var app = new JobApplication(personal, work, refs, coverLetter);
+
+            applicationId = await ApplicationService.SubmitApplicationAsync(app);
+            submitted = true;
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Submission failed: {ex.Message}";
+        }
+        finally
+        {
+            isProcessing = false;
+        }
+    }
+
+    // ── Helpers ──
+
+    private static string FormatDate(DateTime date) =>
+        date == default ? string.Empty : date.ToString("yyyy-MM-dd");
+
+    private static string FormatDate(DateTime? date) =>
+        date?.ToString("yyyy-MM-dd") ?? string.Empty;
+
+    private static DateTime ParseDate(string? value) =>
+        DateTime.TryParse(value, out var d) ? d : default;
+
+    private static DateTime? ParseNullableDate(string? value) =>
+        DateTime.TryParse(value, out var d) ? d : null;
+
+    // ── Mutable models for form binding ──
+
+    private record WorkEntryModel
+    {
+        public string Company { get; set; } = string.Empty;
+        public string Title { get; set; } = string.Empty;
+        public DateTime StartDate { get; set; }
+        public DateTime? EndDate { get; set; }
+        public bool IsCurrent { get; set; }
+        public string Description { get; set; } = string.Empty;
+    }
+
+    private record ReferenceModel
+    {
+        public string Name { get; set; } = string.Empty;
+        public string Relationship { get; set; } = string.Empty;
+        public string Email { get; set; } = string.Empty;
+        public string Phone { get; set; } = string.Empty;
+    }
+}
+

toolArgs.file_text:
.step-indicator {
    display: flex;
    justify-content: space-between;
    gap: 0.25rem;
    padding: 0;
    counter-reset: step;
}

.step-item {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    padding: 0.75rem 0.25rem;
    border: none;
    background: transparent;
    cursor: pointer;
    position: relative;
    transition: opacity 0.2s;
}

.step-item.future {
    opacity: 0.4;
    cursor: default;
}

.step-item.active .step-circle {
    background-color: var(--bs-primary, #0d6efd);
    color: #fff;
    transform: scale(1.15);
}

.step-item.completed .step-circle {
    background-color: var(--bs-success, #198754);
    color: #fff;
}

.step-item.future .step-circle {
    background-color: var(--bs-secondary-bg, #e9ecef);
    color: var(--bs-secondary, #6c757d);
}

.step-circle {
    width: 2.2rem;
    height: 2.2rem;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    transition: background-color 0.2s, transform 0.2s;
}

.step-label {
    font-size: 0.78rem;
    text-align: center;
    line-height: 1.2;
    font-weight: 500;
}

.step-item.active .step-label {
    color: var(--bs-primary, #0d6efd);
    font-weight: 600;
}

.step-item.completed .step-label {
    color: var(--bs-success, #198754);
}

/* Connector lines between steps */
.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 1.5rem;
    left: calc(50% + 1.3rem);
    width: calc(100% - 2.6rem);
    height: 2px;
    background-color: var(--bs-secondary-bg, #e9ecef);
    z-index: -1;
}

.step-item.completed:not(:last-child)::after {
    background-color: var(--bs-success, #198754);
}

